Write-Output ''
Write-Output 'NEXT:   If DNS fails              -> check DNS server configuration and firewall rules'
Write-Output '        If HTTPS blocked          -> work with firewall team to allow Microsoft Update endpoints'
Write-Output '        If proxy issues           -> verify proxy allows *.windowsupdate.com, *.microsoft.com'
Write-Output '        For TLS/certificate issues -> run WU004 WUTlsCertCheck'

$ErrorActionPreference = 'SilentlyContinue'
Write-Output ''
Write-Output '=== Defender & AV Status Triage ==='
Write-Output ''

$issueCount = 0
$warnCount = 0

# State tracking for signal gap analysis
$hasThirdPartyAV = $false
$thirdPartyAVOn = $false
$defenderPassive = $false
$secCenterAvailable = $true

# --- Check 1: Security Center AV Products ---
try {
    $avProducts = Get-CimInstance -Namespace root/SecurityCenter2 -ClassName AntiVirusProduct -ErrorAction Stop
    if ($null -eq $avProducts -or @($avProducts).Count -eq 0) {
        Write-Output '[!!]  Security Center AV Products'
        Write-Output '       No antivirus products registered in Security Center. Machine may be unprotected.'
        $issueCount++
    } else {
        foreach ($av in @($avProducts)) {
            $pState = [UInt32]$av.productState
            $engineBits = $pState -band 0xF000
            $sigBits    = $pState -band 0x00F0
            $ownerBits  = $pState -band 0x0F00

            $engineState = switch ($engineBits) {
                0x1000 { 'On' }
                0x0000 { 'Off' }
                0x2000 { 'Snoozed' }
                0x3000 { 'Expired' }
                default { "Unknown (0x$($engineBits.ToString('X4')))" }
            }

            $sigState = if ($sigBits -eq 0x0000) { 'Current' } else { 'Outdated' }
            $owner    = if ($ownerBits -eq 0x0100) { 'Microsoft' } else { 'Third-party' }

            $isDefender = ($av.displayName -like '*Windows Defender*' -or $av.displayName -like '*Microsoft Defender*')

            if (-not $isDefender) {
                $hasThirdPartyAV = $true
                if ($engineState -eq 'On') { $thirdPartyAVOn = $true }
            }

            # Ghost detection: verify executable exists on disk
            $isGhost = $false
            $exePath = $av.pathToSignedReportingExe
            if (-not [string]::IsNullOrWhiteSpace($exePath)) {
                # Skip URI-style paths (windowsdefender://) and environment variable paths
                if ($exePath -notlike 'windowsdefender://*' -and $exePath -notlike '%*') {
                    if (-not (Test-Path $exePath)) {
                        $isGhost = $true
                    }
                }
            }

            if ($isGhost) {
                Write-Output "[!!]  Security Center: $($av.displayName)"
                Write-Output "       GHOST REGISTRATION -- product registered but executable not found on disk."
                Write-Output "       Path: $exePath"
                Write-Output '       Intune sees this as the AV, but it is not installed. Run DEF003 DEFThirdPartyAV.'
                $issueCount++
            } elseif (-not $isDefender -and ($engineState -ne 'On')) {
                Write-Output "[!!]  Security Center: $($av.displayName)"
                Write-Output "       State: $engineState, Signatures: $sigState, Origin: $owner."
                Write-Output '       Registered but not actively protecting. Check third-party AV configuration.'
                $issueCount++
            } elseif (-not $isDefender -and $engineState -eq 'On') {
                Write-Output "[i]   Security Center: $($av.displayName)"
                Write-Output "       State: $engineState, Signatures: $sigState, Origin: $owner."
                Write-Output '       Third-party AV is primary. Defender should be in passive mode.'
            } else {
                Write-Output "[OK]  Security Center: $($av.displayName)"
                Write-Output "       State: $engineState, Signatures: $sigState, Origin: $owner."
            }
        }
    }
} catch {
    $secCenterAvailable = $false
    Write-Output '[i]   Security Center AV Products'
    Write-Output '       SecurityCenter2 namespace not available (normal on Windows Server).'
    Write-Output '       Skipping Security Center checks. Defender status checked below.'
}

# --- Check 2: Defender Status (Get-MpComputerStatus) ---
$mpOK = $false
try {
    $mpStatus = Get-MpComputerStatus -ErrorAction Stop
    $mpOK = $true

    $runMode = $mpStatus.AMRunningMode
    $rtpEnabled = $mpStatus.RealTimeProtectionEnabled

    # Running mode verdict
    if ($runMode -eq 'Normal' -and $rtpEnabled) {
        Write-Output '[OK]  Defender Running Mode'
        Write-Output "       Mode: $runMode. Real-time protection: Enabled. Defender is active and protecting."
    } elseif ($runMode -like '*Passive*') {
        $defenderPassive = $true
        if ($hasThirdPartyAV) {
            Write-Output '[i]   Defender Running Mode'
            Write-Output "       Mode: $runMode. This is expected -- a third-party AV is primary."
        } else {
            Write-Output '[!!]  Defender Running Mode'
            Write-Output "       Mode: $runMode but no third-party AV detected in Security Center."
            Write-Output '       A ghost AV registration may be forcing passive mode. Machine may be unprotected.'
            Write-Output '       Run DEF003 DEFThirdPartyAV to investigate.'
            $issueCount++
        }
    } elseif ($runMode -eq 'EDR Block Mode') {
        Write-Output '[i]   Defender Running Mode'
        Write-Output "       Mode: EDR Block Mode. AV is passive but EDR detections are actively blocked."
    } elseif ($runMode -eq 'Normal' -and -not $rtpEnabled) {
        Write-Output '[!!]  Defender Running Mode'
        Write-Output "       Mode: $runMode but Real-time protection is DISABLED."
        Write-Output '       Defender is primary but not scanning files. Run DEF004 DEFRealtimeProtection.'
        $issueCount++
    } else {
        $rtpText = if ($rtpEnabled) { 'Enabled' } else { 'Disabled' }
        Write-Output '[i]   Defender Running Mode'
        Write-Output "       Mode: $runMode. Real-time protection: $rtpText."
    }

    # Definition age
    $sigAge = $mpStatus.AntivirusSignatureAge
    $sigUpdated = $mpStatus.AntivirusSignatureLastUpdated
    $sigDateStr = 'unknown'
    if ($null -ne $sigUpdated -and $sigUpdated -ne [datetime]::MinValue) {
        $sigDateStr = $sigUpdated.ToString('yyyy-MM-dd HH:mm')
    }

    if ($sigAge -gt 3) {
        Write-Output '[!!]  Definition Age'
        Write-Output "       $sigAge day(s) old (last updated: $sigDateStr). Definitions are stale."
        Write-Output '       Run DEF002 DEFDefinitionHealth to diagnose update failures.'
        $issueCount++
    } elseif ($sigAge -gt 1) {
        Write-Output '[!]   Definition Age'
        Write-Output "       $sigAge day(s) old (last updated: $sigDateStr). Slightly behind."
        $warnCount++
    } else {
        Write-Output '[OK]  Definition Age'
        Write-Output "       $sigAge day(s) old (last updated: $sigDateStr). Definitions are current."
    }

    # Scan ages (only if Defender is active, not passive)
    if (-not $defenderPassive) {
        $quickAge = $mpStatus.QuickScanAge
        $fullAge  = $mpStatus.FullScanAge

        if ($fullAge -gt 30) {
            Write-Output '[!]   Scan History'
            Write-Output "       Quick scan: $quickAge day(s) ago. Full scan: $fullAge day(s) ago. No full scan in over 30 days."
            $warnCount++
        } elseif ($quickAge -gt 14) {
            Write-Output '[!]   Scan History'
            Write-Output "       Quick scan: $quickAge day(s) ago. Full scan: $fullAge day(s) ago. No quick scan in over 14 days."
            $warnCount++
        } else {
            Write-Output '[OK]  Scan History'
            Write-Output "       Quick scan: $quickAge day(s) ago. Full scan: $fullAge day(s) ago."
        }
    }

    # Platform info (informational)
    Write-Output '[i]   Platform Info'
    Write-Output "       Product: $($mpStatus.AMProductVersion), Engine: $($mpStatus.AMEngineVersion), NIS Engine: $($mpStatus.NISEngineVersion)."

    # Tamper protection (informational)
    $tamper = $mpStatus.IsTamperProtected
    if ($tamper) {
        Write-Output '[i]   Tamper Protection'
        Write-Output '       Enabled. Defender settings are protected from unauthorized changes.'
    } else {
        Write-Output '[i]   Tamper Protection'
        Write-Output '       Disabled. Defender settings can be modified by local admin or malware.'
    }

} catch {
    Write-Output '[!!]  Defender Status'
    Write-Output "       Get-MpComputerStatus failed: $($_.Exception.Message)"
    Write-Output '       Defender module may not be installed or is in a broken state.'
    $issueCount++
}

# --- Check 3: Core Defender Services ---
$services = @(
    @{ Name = 'WinDefend'; Display = 'Windows Defender Antivirus (WinDefend)'; ExpectedStart = 'Automatic' },
    @{ Name = 'WdNisSvc';  Display = 'Network Inspection Service (WdNisSvc)';  ExpectedStart = 'Manual' }
)

foreach ($svc in $services) {
    $s = Get-Service -Name $svc.Name -ErrorAction SilentlyContinue
    if ($null -eq $s) {
        Write-Output "[!!]  $($svc.Display)"
        Write-Output '       Service not found. Defender may not be installed.'
        $issueCount++
    } else {
        $startType = $s.StartType.ToString()
        $status    = $s.Status.ToString()

        if ($startType -eq 'Disabled') {
            Write-Output "[!!]  $($svc.Display)"
            Write-Output "       DISABLED. Service cannot start. Run DEF008 DEFRemediation."
            $issueCount++
        } elseif ($status -ne 'Running' -and $svc.ExpectedStart -eq 'Automatic') {
            Write-Output "[!!]  $($svc.Display)"
            Write-Output "       $status, start type: $startType. Should be running. Run DEF008 DEFRemediation."
            $issueCount++
        } elseif ($status -ne 'Running' -and $svc.ExpectedStart -eq 'Manual') {
            Write-Output "[OK]  $($svc.Display)"
            Write-Output "       $status, start type: $startType. This is expected -- service starts on demand."
        } else {
            Write-Output "[OK]  $($svc.Display)"
            Write-Output "       $status, start type: $startType. Operational."
        }
    }
}

# --- Check 4: Defender for Endpoint (MDE Sensor) ---
$sense = Get-Service -Name 'Sense' -ErrorAction SilentlyContinue
if ($null -eq $sense) {
    Write-Output '[i]   Defender for Endpoint (Sense)'
    Write-Output '       Sense service not found. Device is not onboarded to MDE (may be expected).'
} else {
    $senseStatus = $sense.Status.ToString()
    $senseStart  = $sense.StartType.ToString()

    if ($senseStart -eq 'Disabled') {
        Write-Output '[!!]  Defender for Endpoint (Sense)'
        Write-Output "       DISABLED. MDE sensor cannot start. Onboard the device or check policies."
        $issueCount++
    } elseif ($senseStatus -ne 'Running') {
        Write-Output '[!!]  Defender for Endpoint (Sense)'
        Write-Output "       $senseStatus, start type: $senseStart. MDE sensor is not running."
        $issueCount++
    } else {
        $onboardReg = Get-ItemProperty -Path 'HKLM:\SOFTWARE\Microsoft\Windows Advanced Threat Protection\Status' -ErrorAction SilentlyContinue
        if ($null -ne $onboardReg -and $onboardReg.OnboardingState -eq 1) {
            $orgId = $onboardReg.OrgId
            Write-Output '[OK]  Defender for Endpoint (Sense)'
            Write-Output "       Running, onboarded. OrgId: $orgId."
        } else {
            Write-Output '[!]   Defender for Endpoint (Sense)'
            Write-Output "       Running but onboarding state unclear. Check MDE portal."
            $warnCount++
        }
    }
}

# --- Check 5: Signal Gap Analysis ---
if ($secCenterAvailable -and $mpOK) {
    if ($defenderPassive -and -not $hasThirdPartyAV) {
        Write-Output '[!!]  Signal Gap Analysis'
        Write-Output '       CRITICAL: Defender is in passive mode but no third-party AV is registered.'
        Write-Output '       A ghost AV registration may be the cause. Machine is likely UNPROTECTED.'
        Write-Output '       Run DEF003 DEFThirdPartyAV to investigate and DEF008 to remediate.'
    } elseif (-not $defenderPassive -and $thirdPartyAVOn) {
        Write-Output '[!!]  Signal Gap Analysis'
        Write-Output '       Defender is in active mode while a third-party AV is also active.'
        Write-Output '       Two AV engines running simultaneously causes severe performance issues.'
        Write-Output '       Run DEF003 DEFThirdPartyAV to resolve the conflict.'
        $issueCount++
    } else {
        Write-Output '[OK]  Signal Gap Analysis'
        Write-Output '       Security Center and Defender ground truth are consistent.'
    }
} else {
    Write-Output '[i]   Signal Gap Analysis'
    Write-Output '       Skipped -- Security Center or Defender status was not available for cross-reference.'
}

# --- Summary ---
Write-Output ''
$totalProblems = $issueCount + $warnCount
if ($totalProblems -eq 0) {
    Write-Output 'RESULT: No issues detected. Defender appears healthy.'
} elseif ($issueCount -gt 0 -and $warnCount -gt 0) {
    Write-Output "RESULT: $issueCount issue(s) and $warnCount warning(s) found. Review items marked [!!] and [!] above."
} elseif ($issueCount -gt 0) {
    Write-Output "RESULT: $issueCount issue(s) found. Review items marked [!!] above."
} else {
    Write-Output "RESULT: $warnCount warning(s) found. Review items marked [!] above."
}
Write-Output ''
Write-Output 'NEXT:   If Defender not running       -> restart WinDefend service or run DEF008 DEFRemediation'
Write-Output '        If definitions stale          -> run DEF002 DEFDefinitionHealth'
Write-Output '        If third-party AV detected    -> run DEF003 DEFThirdPartyAV'
Write-Output '        If passive mode unexpected    -> run DEF003 DEFThirdPartyAV (likely ghost registration)'
Write-Output '        If RTP disabled               -> run DEF004 DEFRealtimeProtection'
Write-Output '        If Security Center mismatch   -> run DEF003 DEFThirdPartyAV'

$ErrorActionPreference = 'SilentlyContinue'
Write-Output ''
Write-Output '=== Defender Definition & Signature Health ==='
Write-Output ''

$issueCount = 0
$warnCount  = 0

# ---------------------------------------------------------------
# Check 1: Definition Age Analysis (hourly precision)
# ---------------------------------------------------------------
Write-Output '--- Definition Age ---'
$mpStatus = $null
$mpOK     = $false
try {
    $mpStatus = Get-MpComputerStatus -ErrorAction Stop
    if ($null -ne $mpStatus) { $mpOK = $true }
} catch { }

if (-not $mpOK) {
    Write-Output '[!!]  Defender Status Unavailable'
    Write-Output '       Get-MpComputerStatus returned no data. WMI provider may be unregistered.'
    Write-Output '       On Server 2022 this is a known issue. Run: Register-CimProvider to restore.'
    Write-Output '       Remaining checks that depend on Defender status will be skipped.'
    $issueCount++
} else {
    $nowUtc = [DateTime]::UtcNow

    # --- Antivirus Signatures ---
    $avAge       = $mpStatus.AntivirusSignatureAge
    $avUpdated   = $mpStatus.AntivirusSignatureLastUpdated
    if ($avAge -eq 65535) {
        Write-Output '[!!]  Antivirus Signatures'
        Write-Output '       NEVER UPDATED. Definitions have not been downloaded since OS installation.'
        Write-Output '       This is a critical failure. The update pipeline is completely broken.'
        $issueCount++
    } else {
        $avHours   = -1
        $avDateStr = 'unknown'
        if ($null -ne $avUpdated -and $avUpdated -ne [datetime]::MinValue) {
            $avHours   = [Math]::Round(($nowUtc - $avUpdated.ToUniversalTime()).TotalHours, 1)
            $avDateStr = $avUpdated.ToUniversalTime().ToString('yyyy-MM-dd HH:mm') + ' UTC'
        }
        if ($avHours -gt 48) {
            Write-Output '[!!]  Antivirus Signatures'
            Write-Output "       $avHours hours old (last updated: $avDateStr). Definitions are critically stale."
            Write-Output '       Run checks below to identify why updates are failing.'
            $issueCount++
        } elseif ($avHours -gt 24) {
            Write-Output '[!]   Antivirus Signatures'
            Write-Output "       $avHours hours old (last updated: $avDateStr). Definitions are behind."
            $warnCount++
        } elseif ($avHours -ge 0) {
            Write-Output '[OK]  Antivirus Signatures'
            Write-Output "       $avHours hours old (last updated: $avDateStr). Definitions are current."
        } else {
            Write-Output '[i]   Antivirus Signatures'
            Write-Output "       Age: $avAge day(s). Unable to calculate hourly precision (timestamp unavailable)."
        }
    }

    # --- Antispyware Signatures ---
    $asAge     = $mpStatus.AntispywareSignatureAge
    $asUpdated = $mpStatus.AntispywareSignatureLastUpdated
    if ($asAge -eq 65535) {
        Write-Output '[!!]  Antispyware Signatures'
        Write-Output '       NEVER UPDATED since OS installation.'
        $issueCount++
    } else {
        $asHours   = -1
        $asDateStr = 'unknown'
        if ($null -ne $asUpdated -and $asUpdated -ne [datetime]::MinValue) {
            $asHours   = [Math]::Round(($nowUtc - $asUpdated.ToUniversalTime()).TotalHours, 1)
            $asDateStr = $asUpdated.ToUniversalTime().ToString('yyyy-MM-dd HH:mm') + ' UTC'
        }
        if ($asHours -gt 48) {
            Write-Output '[!!]  Antispyware Signatures'
            Write-Output "       $asHours hours old (last updated: $asDateStr). Critically stale."
            $issueCount++
        } elseif ($asHours -gt 24) {
            Write-Output '[!]   Antispyware Signatures'
            Write-Output "       $asHours hours old (last updated: $asDateStr). Behind."
            $warnCount++
        } elseif ($asHours -ge 0) {
            Write-Output '[OK]  Antispyware Signatures'
            Write-Output "       $asHours hours old (last updated: $asDateStr). Current."
        } else {
            Write-Output '[i]   Antispyware Signatures'
            Write-Output "       Age: $asAge day(s). Hourly precision unavailable."
        }
    }

    # --- NIS Signatures ---
    $nisAge     = $mpStatus.NISSignatureAge
    $nisUpdated = $mpStatus.NISSignatureLastUpdated
    if ($nisAge -eq 65535) {
        Write-Output '[!!]  NIS (Network Inspection) Signatures'
        Write-Output '       NEVER UPDATED since OS installation.'
        $issueCount++
    } else {
        $nisHours   = -1
        $nisDateStr = 'unknown'
        if ($null -ne $nisUpdated -and $nisUpdated -ne [datetime]::MinValue) {
            $nisHours   = [Math]::Round(($nowUtc - $nisUpdated.ToUniversalTime()).TotalHours, 1)
            $nisDateStr = $nisUpdated.ToUniversalTime().ToString('yyyy-MM-dd HH:mm') + ' UTC'
        }
        if ($nisHours -gt 48) {
            Write-Output '[!!]  NIS (Network Inspection) Signatures'
            Write-Output "       $nisHours hours old (last updated: $nisDateStr). Critically stale."
            $issueCount++
        } elseif ($nisHours -gt 24) {
            Write-Output '[!]   NIS (Network Inspection) Signatures'
            Write-Output "       $nisHours hours old (last updated: $nisDateStr). Behind."
            $warnCount++
        } elseif ($nisHours -ge 0) {
            Write-Output '[OK]  NIS (Network Inspection) Signatures'
            Write-Output "       $nisHours hours old (last updated: $nisDateStr). Current."
        } else {
            Write-Output '[i]   NIS (Network Inspection) Signatures'
            Write-Output "       Age: $nisAge day(s). Hourly precision unavailable."
        }
    }
}

Write-Output ''

# ---------------------------------------------------------------
# Check 2: Update Source Configuration
# ---------------------------------------------------------------
Write-Output '--- Update Source Configuration ---'

$sigUpdPath = 'HKLM:\SOFTWARE\Policies\Microsoft\Windows Defender\Signature Updates'
$sigUpdReg  = $null
try { $sigUpdReg = Get-ItemProperty -Path $sigUpdPath -ErrorAction Stop } catch { }

$fallbackOrder = $null
if ($null -ne $sigUpdReg) {
    $fallbackOrder = $sigUpdReg.FallbackOrder
}

$sourceConfigured = $false
if (-not [string]::IsNullOrWhiteSpace($fallbackOrder)) {
    $sourceConfigured = $true
    $sources = $fallbackOrder -split '\|'
    $decoded = @()
    foreach ($s in $sources) {
        $s = $s.Trim()
        switch ($s) {
            'InternalDefinitionUpdateServer' { $decoded += 'WSUS/SCCM' }
            'MicrosoftUpdateServer'          { $decoded += 'Microsoft Update' }
            'MMPC'                           { $decoded += 'Microsoft Malware Protection Center (ADL)' }
            'FileShares'                     { $decoded += 'File Share (UNC)' }
            default                          { $decoded += $s }
        }
    }
    $decodedStr = $decoded -join ' -> '

    $hasMSFallback = ($fallbackOrder -match 'MicrosoftUpdateServer' -or $fallbackOrder -match 'MMPC')
    if ($hasMSFallback) {
        Write-Output '[OK]  Signature Update Source (GPO)'
        Write-Output "       FallbackOrder: $decodedStr."
        Write-Output '       Microsoft CDN is included as a fallback. Update path has redundancy.'
    } else {
        Write-Output '[!]   Signature Update Source (GPO)'
        Write-Output "       FallbackOrder: $decodedStr."
        Write-Output '       No Microsoft CDN fallback. If WSUS does not approve Defender definitions,'
        Write-Output '       this machine will never get updates. Add MicrosoftUpdateServer or MMPC to the fallback order.'
        $warnCount++
    }

    # File share source
    $fileShareSrc = $sigUpdReg.DefinitionUpdateFileSharesSources
    if (-not [string]::IsNullOrWhiteSpace($fileShareSrc)) {
        Write-Output "[i]   File Share Source: $fileShareSrc"
    }
} else {
    Write-Output '[OK]  Signature Update Source (GPO)'
    Write-Output '       FallbackOrder not configured by policy. OS default behavior applies'
    Write-Output '       (Microsoft Update with automatic fallback to MMPC).'
}

# ForceUpdateFromMU
if ($null -ne $sigUpdReg) {
    $forceFromMU = $sigUpdReg.ForceUpdateFromMU
    if ($null -ne $forceFromMU) {
        if ($forceFromMU -eq 1) {
            Write-Output '[i]   ForceUpdateFromMU: Enabled. Definitions can be pulled from Microsoft Update even in WSUS environments.'
        } else {
            Write-Output '[i]   ForceUpdateFromMU: Disabled (0). Strict WSUS-only for definition updates.'
        }
    }
}

# Update interval and catchup
if ($null -ne $sigUpdReg) {
    $interval = $sigUpdReg.SignatureUpdateInterval
    $catchup  = $sigUpdReg.SignatureUpdateCatchupInterval
    $battery  = $sigUpdReg.DisableScheduledSignatureUpdateOnBattery

    $parts = @()
    if ($null -ne $interval) {
        if ($interval -eq 0) {
            Write-Output '[!!]  Signature Update Interval'
            Write-Output '       Set to 0 -- signature polling is COMPLETELY DISABLED by policy.'
            Write-Output '       Definitions will never auto-update. This is the most common cause of stale definitions.'
            $issueCount++
        } else {
            $parts += "Update check every $interval hour(s)"
        }
    }
    if ($null -ne $catchup) {
        $parts += "catch-up after $catchup day(s) of missed updates"
    }
    if ($parts.Count -gt 0) {
        Write-Output "[i]   Update Schedule: $($parts -join '. ')."
    }

    if ($null -ne $battery -and $battery -eq 1) {
        Write-Output '[!]   Battery Policy'
        Write-Output '       DisableScheduledSignatureUpdateOnBattery = 1. Updates are blocked while on battery.'
        Write-Output '       Laptops may fall out of definition compliance over weekends or remote work.'
        $warnCount++
    }
}

# Co-Management sabotage check
$coMgmtPath = 'HKLM:\SOFTWARE\Policies\Microsoft\Windows\WindowsUpdate'
$coMgmtReg  = $null
try { $coMgmtReg = Get-ItemProperty -Path $coMgmtPath -ErrorAction Stop } catch { }
if ($null -ne $coMgmtReg) {
    $setPolicyDriven = $coMgmtReg.SetPolicyDrivenUpdateSourceForOtherUpdates
    if ($null -ne $setPolicyDriven -and $setPolicyDriven -eq 1) {
        Write-Output '[!]   Co-Management Update Source Override'
        Write-Output '       SetPolicyDrivenUpdateSourceForOtherUpdates = 1.'
        Write-Output '       Co-Management is redirecting Defender updates away from WSUS to the cloud.'
        Write-Output '       If the corporate firewall blocks Microsoft CDN endpoints, definitions will fail'
        Write-Output '       with 0x8024402C errors despite local WSUS being correctly configured.'
        $warnCount++
    }
}

Write-Output ''

# ---------------------------------------------------------------
# Check 3: Update Source Connectivity
# ---------------------------------------------------------------
Write-Output '--- Update Source Connectivity ---'

$cdnEndpoints = @(
    @{ Host = 'definitionupdates.microsoft.com'; Desc = 'Primary CDN for Security Intelligence updates' },
    @{ Host = 'go.microsoft.com';                Desc = 'Alternate Download Location (ADL) for cumulative catch-up updates' }
)

foreach ($ep in $cdnEndpoints) {
    $reachable = $false
    try {
        $tcp = New-Object System.Net.Sockets.TcpClient
        $result = $tcp.BeginConnect($ep.Host, 443, $null, $null)
        $waited = $result.AsyncWaitHandle.WaitOne(3000, $false)
        if ($waited -and $tcp.Connected) {
            $reachable = $true
        }
        $tcp.Close()
    } catch { }

    if ($reachable) {
        Write-Output "[OK]  $($ep.Host):443 -- Reachable."
        Write-Output "       $($ep.Desc)."
    } else {
        $icon = if ($ep.Host -eq 'definitionupdates.microsoft.com') { '[!!]' } else { '[!] ' }
        Write-Output "$icon  $($ep.Host):443 -- UNREACHABLE (3s timeout)."
        Write-Output "       $($ep.Desc)."
        Write-Output '       Definitions cannot be downloaded from this endpoint. Check firewall/proxy rules.'
        if ($ep.Host -eq 'definitionupdates.microsoft.com') { $issueCount++ } else { $warnCount++ }
    }
}

# Helpful WSUS reference (not duplicating WU002's check)
if ($sourceConfigured -and $fallbackOrder -match 'InternalDefinitionUpdateServer') {
    Write-Output '[i]   WSUS/SCCM is in the fallback order.'
    Write-Output '       To verify WSUS reachability, run WU002 WUPolicyAudit (includes WSUS TCP check).'
}

Write-Output ''

# ---------------------------------------------------------------
# Check 4: Recent Update Failure Events (last 48h)
# ---------------------------------------------------------------
Write-Output '--- Recent Update Events (last 48h) ---'

$lookbackHours = 48
$startTime     = (Get-Date).AddHours(-$lookbackHours)

# HRESULT translation table
$hresultMap = @{
    '0x8024002E' = 'WU_E_WU_DISABLED -- Windows Update service disabled or access blocked by policy'
    '0x8024402C' = 'WU_E_PT_WINHTTP_NAME_NOT_RESOLVED -- DNS failure for update server'
    '0x80072EE7' = 'ERROR_INTERNET_NAME_NOT_RESOLVED -- DNS failure for Microsoft CDN endpoints'
    '0x80072EFD' = 'ERROR_INTERNET_CANNOT_CONNECT -- Connection timed out to update server'
    '0x80240022' = 'WU_E_ALL_UPDATES_FAILED -- Signature payload corrupted in transit'
    '0x8050800C' = 'ERR_MP_BAD_INPUT_DATA -- Downloaded definitions incompatible with current engine version'
    '0x80508020' = 'ERR_MP_BAD_CONFIGURATION -- Internal engine config error, needs service restart'
    '0x800106BA' = 'RPC server unavailable -- Defender service crashed or MpCmdRun.exe missing'
    '0x80070643' = 'ERROR_INSTALL_FAILURE -- MSI/extraction failure during signature injection'
}

$eventLogName = 'Microsoft-Windows-Windows Defender/Operational'
$failEvents   = $null
$succEvents   = $null

try {
    $failEvents = Get-WinEvent -FilterHashtable @{
        LogName   = $eventLogName
        Id        = 2001, 2003
        StartTime = $startTime
    } -ErrorAction Stop
} catch { }

try {
    $succEvents = Get-WinEvent -FilterHashtable @{
        LogName   = $eventLogName
        Id        = 2000
        StartTime = $startTime
    } -ErrorAction Stop
} catch { }

$failCount = 0
if ($null -ne $failEvents) { $failCount = @($failEvents).Count }

if ($failCount -gt 0) {
    $latestFail = @($failEvents)[0]
    $failTimeStr = $latestFail.TimeCreated.ToString('yyyy-MM-dd HH:mm')
    $failId      = $latestFail.Id

    # Extract HRESULT from event message
    $failMsg     = $latestFail.Message
    $hresultCode = ''
    $hresultDesc = ''
    if ($failMsg -match '0x[0-9A-Fa-f]{8}') {
        $hresultCode = $Matches[0].ToUpper()
        # Normalize to match our table keys (with lowercase x)
        $lookupKey = '0x' + $hresultCode.Substring(2)
        if ($hresultMap.ContainsKey($lookupKey)) {
            $hresultDesc = $hresultMap[$lookupKey]
        }
    }

    if ($failCount -gt 5) {
        Write-Output '[!!]  Persistent Update Failures'
        Write-Output "       $failCount signature update failures in the last ${lookbackHours}h. Update pipeline is broken."
    } else {
        Write-Output '[!!]  Signature Update Failure Detected'
        Write-Output "       $failCount failure(s) in the last ${lookbackHours}h."
    }

    $eventTypeStr = if ($failId -eq 2001) { 'Signature update failed' } else { 'Engine update failed' }
    Write-Output "       Most recent (Event $failId): $eventTypeStr at $failTimeStr."

    if (-not [string]::IsNullOrWhiteSpace($hresultCode)) {
        if (-not [string]::IsNullOrWhiteSpace($hresultDesc)) {
            Write-Output "       Error: $hresultCode -- $hresultDesc."
        } else {
            Write-Output "       Error: $hresultCode (not in known HRESULT table)."
        }
    }
    $issueCount++
} else {
    Write-Output '[OK]  No signature update failures in the last 48 hours.'
}

# Report last success
if ($null -ne $succEvents -and @($succEvents).Count -gt 0) {
    $latestSucc    = @($succEvents)[0]
    $succTimeStr   = $latestSucc.TimeCreated.ToString('yyyy-MM-dd HH:mm')
    Write-Output "[i]   Last successful update: $succTimeStr (Event 2000)."
} else {
    if ($mpOK) {
        $avAge2 = $mpStatus.AntivirusSignatureAge
        if ($avAge2 -gt 2) {
            Write-Output '[!]   No successful signature updates found in the last 48h event log.'
            Write-Output '       Combined with stale definitions, the update pipeline may be completely blocked.'
            $warnCount++
        } else {
            Write-Output '[i]   No Event 2000 (success) found in the 48h window, but definitions are recent.'
            Write-Output '       Updates may have occurred before the lookback window.'
        }
    }
}

