    $enableFw = $null
    try {
        $regObj = Get-ItemProperty -Path $regPath -ErrorAction Stop
        if ($null -ne $regObj -and ($regObj.PSObject.Properties.Name -contains 'EnableFirewall')) {
            $enableFw = [int]$regObj.EnableFirewall
