        @{ Pattern = '^\w:\\\*';                 Severity = 'ISSUE'; Reason = 'Root wildcard. All files on this volume are excluded.' }
        @{ Pattern = '(?i)^\w:\\Windows\\?$';    Severity = 'ISSUE'; Reason = 'Entire Windows directory excluded. Critical system files unscanned.' }
