# Helper: read registry value safely
function Get-RegVal {
    param([string]$Path, [string]$Name)
    try {
        $item = Get-ItemProperty -Path $Path -Name $Name -ErrorAction Stop
        if ($null -ne $item) {
            $val = $item.$Name
            if ($null -ne $val) { return $val }
        }
    } catch { }
    return $null
}

