if (Test-Path -Path $gpoAsrPath) {
    try {
        $gpoAsrItem = Get-Item -Path $gpoAsrPath -ErrorAction Stop
        foreach ($prop in $gpoAsrItem.Property) {
            $val = Get-RegVal -Path $gpoAsrPath -Name $prop
            if ($null -ne $val) { $gpoAsrRules[$prop.ToLower()] = $val }
