    4 = 'AES-CBC 256-bit'
    6 = 'XTS-AES 128-bit'
    7 = 'XTS-AES 256-bit'
}

# TPM usage decode table
$tpmUsageMap = @{
    0 = 'Do not allow'
    1 = 'Require'
    2 = 'Allow'
}

if (-not $fveExists) {
