$mdmWinsValue = $null
$mdmWinsSource = $null

# Research doc path (authoritative per Microsoft docs)
$mdmWinsPath1 = 'HKLM:\SOFTWARE\Microsoft\PolicyManager\current\device\ControlPolicyConflict'
